import { createContext, useEffect, useState } from "react";
import axios from "axios";

export const StoreContext = createContext();

const StoreContextProvider = (props) => {
  const [cartItems, setCartItems] = useState({});
  const [token, setToken] = useState("");
  const [loaded, setLoaded] = useState(true);
  const [food_list, setFoodList] = useState([]);

  const url = "http://localhost:5000";

  // ================= ADD TO CART =================
  const addToCart = async (itemId) => {
    setCartItems((prev) => ({
      ...prev,
      [itemId]: (prev[itemId] || 0) + 1,
    }));

    if (!token) return;

    try {
      await axios.post(
        url + "/api/cart/add",
        { itemId },
        {
          headers: {
            Authorization: `Bearer ${token}`,
          },
        }
      );
    } catch (error) {
      console.error("Add to cart error:", error.response?.data || error.message);
    }
  };

  // ================= REMOVE FROM CART =================
  const removeFromCart = async (itemId) => {
    setCartItems((prev) => ({
      ...prev,
      [itemId]: Math.max(prev[itemId] - 1, 0),
    }));

    if (!token) return;

    try {
      await axios.post(
        url + "/api/cart/remove",
        { itemId },
        {
          headers: {
            Authorization: `Bearer ${token}`,
          },
        }
      );
    } catch (error) {
      console.error("Remove from cart error:", error.response?.data || error.message);
    }
  };

  // ================= TOTAL AMOUNT =================
  const getTotalCartAmount = () => {
    let totalAmount = 0;

    for (const item in cartItems) {
      if (cartItems[item] > 0) {
        const itemInfo = food_list.find(
          (product) => product._id === item
        );
        if (itemInfo) {
          totalAmount += itemInfo.price * cartItems[item];
        }
      }
    }
    return totalAmount;
  };

  // ================= FETCH FOOD LIST =================
  const fetchFoodList = async () => {
    try {
      const response = await axios.get(url + "/api/food/list");
      setLoaded(true);
      return response.data.data;
    } catch (error) {
      console.error("Food list error:", error);
      setLoaded(false);
      return [];
    }
  };

  // ================= LOAD CART DATA =================
  const loadCartData = async (savedToken) => {
    try {
      const response = await axios.post(
        url + "/api/cart/get",
        {},
        {
          headers: {
            Authorization: `Bearer ${savedToken}`,
          },
        }
      );
      setCartItems(response.data.cartData || {});
    } catch (error) {
      console.error("Load cart error:", error.response?.data || error.message);
    }
  };

  // ================= INITIAL LOAD =================
  useEffect(() => {
    async function loadData() {
      const fetchedFoodList = await fetchFoodList();
      setFoodList(fetchedFoodList);

      const savedToken = localStorage.getItem("token");
      if (savedToken) {
        setToken(savedToken);
        await loadCartData(savedToken);
      }
    }

    loadData();
  }, []);

  // ================= CONTEXT VALUE =================
  const contextValue = {
    food_list,
    cartItems,
    setCartItems,
    addToCart,
    removeFromCart,
    getTotalCartAmount,
    url,
    token,
    setToken,
    loaded,
  };

  return (
    <StoreContext.Provider value={contextValue}>
      {props.children}
    </StoreContext.Provider>
  );
};

export default StoreContextProvider;
